    vatSubjRows: [['— الشروط الأساسية —','ثلاثة أشياء يجب استيفاؤها للمسؤولية الضريبية'],['1. نشاط تجاري','يجب عليك ممارسة نشاط تجاري — ليس هواية أو عمل موظف','§ 2-1(1)'],['2. تسليم السلع/الخدمات','يجب أن تكون هناك معاملة — تسليم مقابل عوض (دفع)','§ 1-3(1)a'],['3. حد الإيرادات','إيرادات تتجاوز 50 000 kr خلال 12 شهراً','§ 2-1(1)'],['— من يجب عليه التسجيل؟ —',''],['النشاطات التجارية فوق 50 000 kr','يجب عليهم التسجيل في سجل الضريبة','§ 2-1(1)'],['المنظمات الخيرية','حد أعلى: 140 000 kr','§ 2-1(1)'],['الفعاليات الرياضية','حد منفصل: 3 000 000 kr','§ 2-1(1)'],['— المفاهيم الرئيسية —',''],['ما هو « النشاط التجاري »؟','نشاط مستقل ودائم ذو طبيعة اقتصادية وقابل لتحقيق الربح. الهوايات والمهام لمرة واحدة لا تعتبر عادةً نشاطاً تجارياً.'],['ما هي « الإيرادات »؟','تسليم السلع أو الخدمات مقابل عوض. الهدايا والتعويض والمنح لا تعتبر عادةً إيرادات.','§ 1-3(1)a'],['من هو « المكلف بالضريبة »؟','كيان مسجل (أو مطلوب التسجيل) في سجل الضريبة، ملزم بحساب ودفع الضريبة.','§ 1-3(1)d'],['التسجيل الطوعي؟','مالكو العقارات التجارية قد يسجلون طواعية للحصول على حق خصم الضريبة الوارد.','§ 2-3']],
    vatSubjTitle:'من هو خاضع للضريبة؟', vatSubjDesc:'النشاط التجاري · حد الإيرادات · التزام التسجيل',
